generated_oml:
// Sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "senses motor current from the permanent‑magnet synchronous motor"
    DTDFVocab:producedData I_M_Stream
]

instance MotorPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "senses angular position at the motor shaft of the permanent‑magnet synchronous motor"
    DTDFVocab:producedData MotorEncoderAngleStream
]

instance GearboxPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "sensors angular position behind the cycloidal gearbox"
    DTDFVocab:producedData GearboxEncoderAngleStream
]

// Data transmitted (sensor streams)
instance I_M_Stream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorEncoderAngleStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorPositionEncoder
]

instance GearboxEncoderAngleStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxPositionEncoder
]

// Derived simulated data streams
instance SimulatedMotorAngleStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SimulinkMotorSimModel
]

instance SimulatedGearboxAngleStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SimulinkGearboxSimModel
]

instance SimulatedOutputAngleStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SimulinkGearwheelSimModel
]

// Data traces stored in the twin
instance I_M_DataTrace : DTDFVocab:Data [
    base:desc "sensor data trace of motor current (I_M) recorded as part of the digital twin"
    DTDFVocab:fromData I_M_Stream
    DTDFVocab:inputTo MQTTEnabler
]

instance MotorEncoderAngle_DataTrace : DTDFVocab:Data [
    base:desc "data trace of motor encoder angle recorded from the motor shaft"
    DTDFVocab:fromData MotorEncoderAngleStream
    DTDFVocab:inputTo MQTTEnabler
]

instance GearboxEncoderAngle_DataTrace : DTDFVocab:Data [
    base:desc "data trace of gearbox encoder angle recorded behind the cycloidal gearbox"
    DTDFVocab:fromData GearboxEncoderAngleStream
    DTDFVocab:inputTo MQTTEnabler
]

instance Torque_DataTrace : DTDFVocab:Data [
    base:desc "derived torque data trace based on residual torque signals"
    DTDFVocab:fromData I_M_Stream
    DTDFVocab:inputTo SimulinkEnabler
]

instance AngularVelocity_DataTrace : DTDFVocab:Data [
    base:desc "derived angular velocity trace extracted from encoder and current data streams"
    DTDFVocab:fromData I_M_Stream
    DTDFVocab:inputTo SimulinkEnabler
]

instance Acceleration_DataTrace : DTDFVocab:Data [
    base:desc "derived angular acceleration trace extracted from encoder and current data streams"
    DTDFVocab:fromData I_M_Stream
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulatedMotorAngle_DataTrace : DTDFVocab:Data [
    base:desc "simulation model output trace (~r_M) from Simulink motor model"
    DTDFVocab:fromData SimulatedMotorAngleStream
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulatedGearboxAngle_DataTrace : DTDFVocab:Data [
    base:desc "simulation model output trace (~r_G) from Simulink gearbox model"
    DTDFVocab:fromData SimulatedGearboxAngleStream
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulatedOutputAngle_DataTrace : DTDFVocab:Data [
    base:desc "simulation model output trace (~r_out) from Simulink gearwheel model"
    DTDFVocab:fromData SimulatedOutputAngleStream
    DTDFVocab:inputTo SimulinkEnabler
]

// Models
instance SysMLEngineeringModel : DTDFVocab:Model [
    base:desc "Engineering model of the first axis written in SysML"
    DTDFVocab:inputTo SysMLEnabler
]

instance SimulinkMotorSimModel : DTDFVocab:Model [
    base:desc "Simulink simulation model of the permanent‑magnet synchronous motor producing torque and angular velocity traces"
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulinkGearboxSimModel : DTDFVocab:Model [
    base:desc "Simulink simulation model of the gear transmission and cycloidal gearbox producing torque and angular velocity traces"
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulinkGearwheelSimModel : DTDFVocab:Model [
    base:desc "Simulink simulation model of the gearwheel producing torque and angular velocity traces"
    DTDFVocab:inputTo SimulinkEnabler
]

// Enablers
instance SysMLEnabler : DTDFVocab:Enabler [
    base:desc "SysML tool used for structural modelling of the asset"
    DTDFVocab:enables ModelingService
]

instance SimulinkEnabler : DTDFVocab:Enabler [
    base:desc "Simulink used for executable simulation of motor, gearbox, and gearwheel models"
    DTDFVocab:enables FrictionParameterEstimationService
]

instance MQTTEnabler : DTDFVocab:Enabler [
    base:desc "MQTT protocol facilitating real‑time sensor data streaming to digital twin"
    DTDFVocab:enables RealTimeMonitoringService
]

instance DashboardEnabler : DTDFVocab:Enabler [
    base:desc "Custom dashboard for data visualization"
    DTDFVocab:enables DashboardVisualizationService
]

instance AASEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell representing the digital twin context"
    DTDFVocab:enables AssetAdministrationShellService
]

// Services
instance RealTimeMonitoringService : DTDFVocab:Service [
    base:desc "Real‑time monitoring of joint dynamics, using MQTT data streams and visualisation"
    DTDFVocab:provides RealTimeMonitoringInsight
]

instance FrictionParameterEstimationService : DTDFVocab:Service [
    base:desc "Estimates friction parameters by comparing measured and simulated torque signals"
    DTDFVocab:provides FrictionParameterExtractionInsight, WearInducedFrictionChangeInsight, MotorCurrentSetpointRecommendationAction, TorqueLimitAdjustmentAction
]

instance DashboardVisualizationService : DTDFVocab:Service [
    base:desc "Provides dashboard interface displaying reference, simulated and residual signals for control improvement"
]

instance AssetAdministrationShellService : DTDFVocab:Service [
    base:desc "Service maintaining the asset administration shell context"
]

instance ModelingService : DTDFVocab:Service [
    base:desc "Service that facilitates the creation and refinement of SysML engineering models"
]

// Insights
instance RealTimeMonitoringInsight : DTDFVocab:Insight [
    base:desc "Real‑time monitoring of joint dynamics through sensor streams."
]

instance FrictionParameterExtractionInsight : DTDFVocab:Insight [
    base:desc "Extraction of friction parameters from residual torque signals."
]

instance WearInducedFrictionChangeInsight : DTDFVocab:Insight [
    base:desc "Identification of wear‑induced friction changes in the axis."
]

// Actions
instance MotorCurrentSetpointRecommendationAction : DTDFVocab:Action [
    base:desc "Recommend motor current setpoints to maintain positional accuracy."
    DTDFVocab:IsAutomatic true
]

instance TorqueLimitAdjustmentAction : DTDFVocab:Action [
    base:desc "Recommend torque limits to avoid excessive load and maintain control accuracy."
    DTDFVocab:IsAutomatic true
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A single digital shadow comprising a structural engineering model, three simulation models (motor, gearbox, gearwheel), a processing component that consumes sensor traces and generates computed traces, and a visualization dashboard; all elements conform to the reference Digital Shadow Reference Model."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operated phase only – the twin is built from manufacturing data yet continuously updated during operation to reflect wear‑induced friction changes."
]

